#include <bits/stdc++.h>
using namespace std;
int n,a[16003],ans=-(1<<30);
bool b[16003];
vector<int> g[16003];
int dfs(int x){
    b[x]=1;
    int sum=a[x],len=g[x].size();
    for(int i=0;i<len;i++)
        if(!b[g[x][i]]){
            int t=dfs(g[x][i]);
            if(t>0)
                sum+=t;
        }
    ans=max(ans,sum);
    return sum;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)
        cin>>a[i];
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v),g[v].push_back(u);
    }
    dfs(1);
    cout<<ans;
    return 0;
}
